def plan():
    # 1. Define stores and search term
    stores = [
        "http://localhost:8081",
        "http://localhost:8082",
        "http://localhost:8083",
        "http://localhost:8084",
    ]
    search_term = "Crucial MX500"
    mx500_offers = []

    # 2. For each store, open the homepage and search for Crucial MX500 products
    for store in stores:
        opened = open_page(store)
        if not opened:
            continue

        # Use helper to get a search/results page URL for Crucial MX500
        search_results_url = search_on_page(store, search_term)
        if not search_results_url:
            close_page()
            continue

        opened_results = open_page(search_results_url)
        if not opened_results:
            close_page()
            continue

        # 3. Extract Crucial MX500 product entries from the search results
        products_info_str = extract_information_from_page(
            "List all Crucial MX500 product offers on this page with their capacities/sizes and full product URLs. "
            "Return them in this simple format: capacity=500GB,url=http://...;capacity=1TB,url=http://...;"
        )

        # 4. Parse the extracted info string into Python data
        if products_info_str:
            entries = products_info_str.split(";")
            for entry in entries:
                entry = entry.strip()
                if not entry:
                    continue
                parts = entry.split(",")
                capacity = ""
                url = ""
                for p in parts:
                    p = p.strip()
                    if p.startswith("capacity="):
                        capacity = p[len("capacity="):].strip()
                    elif p.startswith("url="):
                        url = p[len("url="):].strip()
                if capacity and url:
                    mx500_offers.append({"capacity": capacity, "url": url})

        close_page()

    # 5. Helper to convert capacity string to GB as integer
    def capacity_to_gb(cap_str: str) -> int:
        s = cap_str.upper().strip()
        if s.endswith("TB"):
            num_str = s[:-2].strip()
            try:
                value = float(num_str)
            except ValueError:
                return 0
            return int(value * 1024)
        if s.endswith("GB"):
            num_str = s[:-2].strip()
            try:
                value = float(num_str)
            except ValueError:
                return 0
            return int(value)
        return 0

    # 6. Determine the largest available MX500 capacity
    largest_capacity_gb = 0
    for offer in mx500_offers:
        cap_gb = capacity_to_gb(offer["capacity"])
        if cap_gb > largest_capacity_gb:
            largest_capacity_gb = cap_gb

    # 7. Collect offers that match the largest capacity
    largest_offers_urls = []
    if largest_capacity_gb > 0:
        for offer in mx500_offers:
            if capacity_to_gb(offer["capacity"]) == largest_capacity_gb:
                largest_offers_urls.append(offer["url"])

    # 8. Prepare final result string
    if largest_offers_urls:
        final_result = "###".join(largest_offers_urls)
    else:
        final_result = "Done"

    # 9. Open the solution page
    open_page("http://localhost:8085")

    # 10. Fill in the final result and submit
    fill_text_field("Type your final answer here...", final_result)
    press_button("Submit Final Result")

